mapper.select:
SELECT o.id, o.order_no, o.price, o.status, o.create_time, o.product_id, p.title AS product_title, p.images AS product_cover_image, c.name AS campus_name, o.buyer_id, ub.nick_name AS buyer_nick_name, ub.phone AS buyer_phone, o.seller_id, us.nick_name AS seller_nick_name, us.phone AS seller_phone FROM trade_order o LEFT JOIN product p ON o.product_id = p.id LEFT JOIN campus c ON o.campus_id = c.id LEFT JOIN user ub ON o.buyer_id = ub.id LEFT JOIN user us ON o.seller_id = us.id
AND o.status = #{status}
ORDER BY o.create_time DESC
